    const clean = str.replace(/^[^,]+,\s*/, "");
    const m = clean.match(/(\d{1,2}) de ([^\s]+) de (\d{4}), (\d{2}):(\d{2})/);
    if (!m) return null;
    const [, dd, mesStr, yyyy, HH, MM] = m;
    const mes = meses[mesStr.toLowerCase()];
    if (mes === undefined) return null;
    return new Date(parseInt(yyyy), mes, parseInt(dd), parseInt(HH), parseInt(MM));
  }

  // ── Tenta ISO primeiro, depois PT-BR
  function parseData(str) {
    return parseISO(str) ?? parsePtBr(str);
  }

  const dataMensagem = parseData(horaMensagemStr);
  const dataAtual    = parseData(tempoAtualStr);

  if (!dataMensagem || !dataAtual) {
    return {
      json: {
        ...base,
        error: "Erro ao interpretar datas",
        _debug: {
          horaMensagemStr,
          tempoAtualStr,
          parsedMensagem: String(dataMensagem),
          parsedAtual:    String(dataAtual)
        }
      }
    };
  }

  const diffMs      = dataAtual.getTime() - dataMensagem.getTime();
  const diffHoras   = Math.floor(diffMs / (1000 * 60 * 60));
  const diffMinutos = Math.floor(diffMs / (1000 * 60)) % 60;

  return {
    json: {
      ...base,
      diferencaHoras:   diffHoras,
      diferencaMinutos: diffMinutos
    }
  };
});

return items.map(item => {
  const timeZone = "America/Sao_Paulo";

  // Hora atual em São Paulo
  const nowSP = new Date(
    new Date().toLocaleString("en-US", { timeZone })
  );
  const hour = nowSP.getHours(); // 0–23

  // Janela permitida: 08:00 <= agora < 22:00
  const withinAllowedTime = hour >= 8 && hour < 22;

  return {
    json: {
      ...item.json,
      currentTime: nowSP.toLocaleString("pt-BR", { timeZone }),
      withinAllowedTime
    }
  };
});

